import { STORAGE_KEYS } from '../constants';

// Local Storage Utilities
export const storage = {
  get: (key) => {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : null;
    } catch (error) {
      console.error(`Error getting ${key} from localStorage:`, error);
      return null;
    }
  },

  set: (key, value) => {
    try {
      localStorage.setItem(key, JSON.stringify(value));
      return true;
    } catch (error) {
      console.error(`Error setting ${key} in localStorage:`, error);
      return false;
    }
  },

  remove: (key) => {
    try {
      localStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error(`Error removing ${key} from localStorage:`, error);
      return false;
    }
  },

  clear: () => {
    try {
      localStorage.clear();
      return true;
    } catch (error) {
      console.error('Error clearing localStorage:', error);
      return false;
    }
  },
};

// Theme Utilities
export const themeUtils = {
  get: () => storage.get(STORAGE_KEYS.THEME) || 'dark',

  set: (theme) => {
    storage.set(STORAGE_KEYS.THEME, theme);
    document.body.setAttribute('data-theme', theme);
  },

  toggle: () => {
    const currentTheme = themeUtils.get();
    const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
    themeUtils.set(newTheme);
    return newTheme;
  },

  init: () => {
    const theme = themeUtils.get();
    document.body.setAttribute('data-theme', theme);
  },
};

// Auth Utilities
export const authUtils = {
  getToken: () => storage.get(STORAGE_KEYS.TOKEN),

  setToken: (token) => storage.set(STORAGE_KEYS.TOKEN, token),

  removeToken: () => storage.remove(STORAGE_KEYS.TOKEN),

  getUser: () => storage.get(STORAGE_KEYS.USER),

  setUser: (user) => storage.set(STORAGE_KEYS.USER, user),

  removeUser: () => storage.remove(STORAGE_KEYS.USER),

  isAuthenticated: () => !!authUtils.getToken(),

  logout: () => {
    authUtils.removeToken();
    authUtils.removeUser();
    storage.remove(STORAGE_KEYS.ROLE);
    storage.remove(STORAGE_KEYS.USERNAME);
    storage.remove(STORAGE_KEYS.WALLET);
  },
};

// Format Utilities
export const formatUtils = {
  currency: (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
    }).format(amount);
  },

  date: (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  },

  dateTime: (dateString) => {
    return new Date(dateString).toLocaleString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  },
};

// Validation Utilities
export const validationUtils = {
  email: (email) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  },

  password: (password) => {
    return password && password.length >= 6;
  },

  required: (value) => {
    return value && value.toString().trim().length > 0;
  },
};

// Debounce Utility
export const debounce = (func, delay) => {
  let timeoutId;
  return (...args) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(null, args), delay);
  };
};

// Error Handler
export const errorHandler = {
  log: (error, context = '') => {
    console.error(`Error${context ? ` in ${context}` : ''}:`, error);
  },

  getMessage: (error) => {
    if (error.response?.data?.message) {
      return error.response.data.message;
    }
    if (error.message) {
      return error.message;
    }
    return 'An unexpected error occurred';
  },
};