import React from 'react';

const Loading = ({
  size = 'medium',
  text = 'Loading...',
  fullScreen = false,
  overlay = false
}) => {
  const containerClass = fullScreen
    ? 'loading-container loading-container--fullscreen'
    : overlay
    ? 'loading-container loading-container--overlay'
    : 'loading-container';

  const spinnerClass = `loading-spinner loading-spinner--${size}`;

  return (
    <div className={containerClass}>
      <div className={spinnerClass}></div>
      {text && <p className="loading-text">{text}</p>}
    </div>
  );
};

// Skeleton loading components
export const SkeletonCard = ({ height = '200px' }) => (
  <div className="skeleton-card" style={{ height }}>
    <div className="skeleton-card__header">
      <div className="skeleton-card__avatar"></div>
      <div className="skeleton-card__title"></div>
    </div>
    <div className="skeleton-card__content">
      <div className="skeleton-card__line"></div>
      <div className="skeleton-card__line skeleton-card__line--short"></div>
    </div>
  </div>
);

export const SkeletonTable = ({ rows = 5, columns = 4 }) => (
  <div className="skeleton-table">
    {Array.from({ length: rows }).map((_, rowIndex) => (
      <div key={rowIndex} className="skeleton-table__row">
        {Array.from({ length: columns }).map((_, colIndex) => (
          <div key={colIndex} className="skeleton-table__cell"></div>
        ))}
      </div>
    ))}
  </div>
);

export const SkeletonText = ({ lines = 3 }) => (
  <div className="skeleton-text">
    {Array.from({ length: lines }).map((_, index) => (
      <div
        key={index}
        className={`skeleton-text__line ${index === lines - 1 ? 'skeleton-text__line--short' : ''}`}
      ></div>
    ))}
  </div>
);

export default Loading;